import React, { useState, useEffect } from 'react';
import Editor from '@monaco-editor/react';
import { Play, CheckCircle, BookOpen, Code, Trophy, MessageCircle, Flame, ChevronRight, Star, Sun, Moon } from 'lucide-react';
import './App.css';

const LANGUAGES = [
  { id: 'python', name: 'Python', color: '#3776ab', icon: '🐍' },
  { id: 'javascript', name: 'JavaScript', color: '#f7df1e', icon: '⚡' },
  { id: 'html', name: 'HTML', color: '#e34c26', icon: '🌐' },
  { id: 'css', name: 'CSS', color: '#264de4', icon: '🎨' }
];

const LESSONS = {
  python: [
    {
      id: 1,
      title: 'Print Statement',
      content: 'In Python, we use print() to show output. Try printing "Hello, World!"',
      code: '# Write your code here\nprint("Hello, World!")',
      expected: 'Hello, World!',
      hint: 'Use print() with your message inside quotes',
      difficulty: 'beginner'
    },
    {
      id: 2,
      title: 'Variables',
      content: 'Variables store data. Create a variable named name with your name and print it.',
      code: '# Create a variable and print it\nname = "Your Name"\nprint(name)',
      expected: 'Your Name',
      hint: 'name = "John" then print(name)',
      difficulty: 'beginner'
    },
    {
      id: 3,
      title: 'Simple Math',
      content: 'Python can do math. Calculate 10 + 5 and print the result.',
      code: '# Calculate and print\nresult = 10 + 5\nprint(result)',
      expected: '15',
      hint: 'Use +, -, *, / for math operations',
      difficulty: 'beginner'
    }
  ],
  javascript: [
    {
      id: 1,
      title: 'Console Log',
      content: 'JavaScript uses console.log() to display output. Print "Hello JS!"',
      code: '// Write your code here\nconsole.log("Hello JS!");',
      expected: 'Hello JS!',
      hint: 'Use console.log() with your message',
      difficulty: 'beginner'
    },
    {
      id: 2,
      title: 'Variables with let',
      content: 'Use let to create variables. Make a variable age = 20 and log it.',
      code: '// Create variable and log\nlet age = 20;\nconsole.log(age);',
      expected: '20',
      hint: 'let variableName = value;',
      difficulty: 'beginner'
    }
  ],
  html: [
    {
      id: 1,
      title: 'Basic Structure',
      content: 'HTML uses tags. Create a heading with h1 tag.',
      code: '<!-- Write HTML here -->\n<h1>My First Page</h1>',
      expected: 'My First Page',
      hint: '<h1>Your text</h1>',
      difficulty: 'beginner'
    },
    {
      id: 2,
      title: 'Paragraph Tag',
      content: 'Use p tag for paragraphs. Create a paragraph saying "I love coding".',
      code: '<!-- Add a paragraph -->\n<p>I love coding</p>',
      expected: 'I love coding',
      hint: '<p>Your paragraph text</p>',
      difficulty: 'beginner'
    }
  ],
  css: [
    {
      id: 1,
      title: 'Change Color',
      content: 'CSS styles HTML. Make text red using color property.',
      code: '/* Style the text */\nh1 {\n  color: red;\n}',
      expected: 'color: red',
      hint: 'selector { property: value; }',
      difficulty: 'beginner'
    },
    {
      id: 2,
      title: 'Background Color',
      content: 'Change background color. Make body background yellow.',
      code: '/* Change background */\nbody {\n  background-color: yellow;\n}',
      expected: 'background-color: yellow',
      hint: 'background-color: colorname;',
      difficulty: 'beginner'
    }
  ]
};

function App() {
  const [selectedLang, setSelectedLang] = useState('python');
  const [currentLesson, setCurrentLesson] = useState(0);
  const [code, setCode] = useState('');
  const [output, setOutput] = useState('');
  const [streak, setStreak] = useState(12);
  const [completed, setCompleted] = useState([]);
  const [xp, setXp] = useState(150);
  const [showHint, setShowHint] = useState(false);
  const [doubts, setDoubts] = useState([]);
  const [doubtMsg, setDoubtMsg] = useState('');
  const [theme, setTheme] = useState('dark');

  const toggleTheme = () => {
    setTheme(theme === 'dark' ? 'light' : 'dark');
  };

  useEffect(() => {
    setCode(LESSONS[selectedLang][currentLesson].code);
    setOutput('');
    setShowHint(false);
  }, [selectedLang, currentLesson]);

  const runCode = () => {
    const lesson = LESSONS[selectedLang][currentLesson];
    let result = '';

    if (selectedLang === 'python') {
      if (code.includes('print(')) {
        const match = code.match(/print\(["\'](.+?)["\']\)/);
        if (match) result = match[1];
        else {
          const varMatch = code.match(/print\((\w+)\)/);
          if (varMatch) {
            const varName = varMatch[1];
            const varLine = code.match(new RegExp(varName + '\\s*=\\s*["\'](.+?)["\']')); 
            if (varLine) result = varLine[1];
          }
          const numMatch = code.match(/print\((\d+\s*[+\-*/]\s*\d+)\)/);
          if (numMatch) {
            try {
              result = eval(numMatch[1]).toString();
            } catch (e) {
              result = 'Error';
            }
          }
        }
      }
    } else if (selectedLang === 'javascript') {
      if (code.includes('console.log(')) {
        const match = code.match(/console\.log\(["\'](.+?)["\']\)/);
        if (match) result = match[1];
        else {
          const varMatch = code.match(/console\.log\((\w+)\)/);
          if (varMatch) {
            const varName = varMatch[1];
            const varLine = code.match(new RegExp(`let\\s+${varName}\\s*=\\s*(\\d+)`));
            if (varLine) result = varLine[1];
          }
        }
      }
    } else if (selectedLang === 'html') {
      const match = code.match(/<h1>(.+?)<\/h1>/) || code.match(/<p>(.+?)<\/p>/);
      if (match) result = match[1];
    } else if (selectedLang === 'css') {
      if (code.includes('color: red')) result = 'color: red';
      else if (code.includes('background-color: yellow')) result = 'background-color: yellow';
    }

    setOutput(result);

    if (result && (lesson.expected === result || result.includes(lesson.expected) || lesson.expected.includes(result))) {
      if (!completed.includes(`${selectedLang}-${currentLesson}`)) {
        setCompleted([...completed, `${selectedLang}-${currentLesson}`]);
        setXp(xp + 10);
      }
    }
  };

  const nextLesson = () => {
    if (currentLesson < LESSONS[selectedLang].length - 1) {
      setCurrentLesson(currentLesson + 1);
    }
  };

  const prevLesson = () => {
    if (currentLesson > 0) {
      setCurrentLesson(currentLesson - 1);
    }
  };

  const sendDoubt = () => {
    if (doubtMsg.trim()) {
      setDoubts([...doubts, { user: 'You', msg: doubtMsg, time: new Date().toLocaleTimeString() }]);
      setDoubtMsg('');
    }
  };

  const lesson = LESSONS[selectedLang][currentLesson];
  const progress = ((completed.filter(c => c.startsWith(selectedLang)).length / LESSONS[selectedLang].length) * 100).toFixed(0);

  return (
    <div className={`min-h-screen ${theme === 'dark' ? 'bg-gray-900 text-white' : 'bg-gray-50 text-gray-900'}`}>
      <header className={`${theme === 'dark' ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200'} border-b px-6 py-4`}>
        <div className="flex items-center justify-between max-w-7xl mx-auto">
          <div className="flex items-center gap-3">
            <div className="bg-gradient-to-r from-blue-500 to-purple-600 p-2 rounded-lg">
              <Code size={24} className="text-white" />
            </div>
            <h1 className="text-2xl font-bold bg-gradient-to-r from-blue-400 to-purple-400 bg-clip-text text-transparent">
              CodeLearn
            </h1>
          </div>
          <div className="flex items-center gap-6">
            <button
              onClick={toggleTheme}
              className={`flex items-center gap-2 px-4 py-2 rounded-full transition-colors ${
                theme === 'dark' ? 'bg-gray-700 hover:bg-gray-600 text-yellow-400' : 'bg-gray-200 hover:bg-gray-300 text-orange-500'
              }`}
            >
              {theme === 'dark' ? <Sun size={20} /> : <Moon size={20} />}
              <span className="font-medium">{theme === 'dark' ? 'Light' : 'Dark'}</span>
            </button>
            <div className="flex items-center gap-2 bg-orange-500/20 px-4 py-2 rounded-full">
              <Flame size={20} className="text-orange-500" />
              <span className="font-bold">{streak} day streak</span>
            </div>
            <div className="flex items-center gap-2 bg-yellow-500/20 px-4 py-2 rounded-full">
              <Trophy size={20} className="text-yellow-500" />
              <span className="font-bold">{xp} XP</span>
            </div>
          </div>
        </div>
      </header>

      <div className={`${theme === 'dark' ? 'bg-gray-800 border-gray-700' : 'bg-white border-gray-200'} border-b px-6 py-3`}>
        <div className="max-w-7xl mx-auto flex gap-3">
          {LANGUAGES.map(lang => (
            <button
              key={lang.id}
              onClick={() => { setSelectedLang(lang.id); setCurrentLesson(0); }}
              className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-all ${
                selectedLang === lang.id 
                  ? `${theme === 'dark' ? 'bg-gray-700 text-white' : 'bg-blue-100 text-blue-900'} ring-2 ring-blue-500` 
                  : `${theme === 'dark' ? 'bg-gray-800 text-gray-400 hover:bg-gray-700' : 'bg-gray-100 text-gray-600 hover:bg-gray-200'}`
              }`}
            >
              <span>{lang.icon}</span>
              <span className="font-medium">{lang.name}</span>
              {completed.filter(c => c.startsWith(lang.id)).length === LESSONS[lang.id].length && <CheckCircle size={16} className="text-green-500" />}
            </button>
          ))}
        </div>
      </div>

      <main className="max-w-7xl mx-auto p-6 grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="space-y-4">
          <div className="bg-gray-800 rounded-xl p-4">
            <div className="flex items-center justify-between mb-2">
              <span className={`text-sm ${theme === 'dark' ? 'text-gray-400' : 'text-gray-600'}`}>Course Progress</span>
              <span className="text-sm font-bold text-blue-400">{progress}%</span>
            </div>
            <div className={`h-2 ${theme === 'dark' ? 'bg-gray-700' : 'bg-gray-200'} rounded-full overflow-hidden`}>
              <div className="h-full bg-gradient-to-r from-blue-500 to-purple-500 transition-all" style={{ width: `${progress}%` }} />
            </div>
          </div>

          <div className="bg-gray-800 rounded-xl p-6">
            <div className="flex items-center gap-2 mb-4">
              <BookOpen size={20} className="text-blue-400" />
              <span className={`text-sm ${theme === 'dark' ? 'text-gray-400' : 'text-gray-600'}`}>Lesson {currentLesson + 1} of {LESSONS[selectedLang].length}</span>
              <span className={`px-2 py-1 rounded text-xs font-bold ${lesson.difficulty === 'beginner' ? 'bg-green-500/20 text-green-400' : 'bg-yellow-500/20 text-yellow-400'}`}>
                {lesson.difficulty.toUpperCase()}
              </span>
            </div>
            <h2 className="text-2xl font-bold mb-4">{lesson.title}</h2>
            <p className={`${theme === 'dark' ? 'text-gray-300' : 'text-gray-700'} mb-6 leading-relaxed`}>{lesson.content}</p>
            {showHint && (
              <div className="bg-yellow-500/10 border border-yellow-500/30 rounded-lg p-4 mb-4">
                <p className="text-yellow-400 text-sm"><strong>Hint:</strong> {lesson.hint}</p>
              </div>
            )}
            <button onClick={() => setShowHint(!showHint)} className={`flex items-center gap-2 px-4 py-2 rounded-lg transition-colors ${
              theme === 'dark' ? 'bg-gray-700 hover:bg-gray-600' : 'bg-gray-200 hover:bg-gray-300'
            }`}>
              <Star size={18} /> {showHint ? 'Hide Hint' : 'Show Hint'}
            </button>
          </div>

          <div className="flex gap-3">
            <button onClick={prevLesson} disabled={currentLesson === 0} className={`flex-1 py-3 rounded-lg font-medium transition-colors ${
              theme === 'dark' ? 'bg-gray-700 hover:bg-gray-600 disabled:opacity-50' : 'bg-gray-200 hover:bg-gray-300 disabled:opacity-50'
            }`}>Previous</button>
            <button onClick={nextLesson} disabled={currentLesson === LESSONS[selectedLang].length - 1} className="flex-1 py-3 bg-blue-600 hover:bg-blue-500 disabled:opacity-50 rounded-lg font-medium flex items-center justify-center gap-2">Next <ChevronRight size={18} /></button>
          </div>

          <div className="bg-gray-800 rounded-xl p-6">
            <div className="flex items-center gap-2 mb-4"><MessageCircle size={20} className="text-purple-400" /><h3 className="font-bold">Ask a Doubt</h3></div>
            <div className="space-y-3 max-h-40 overflow-y-auto mb-4">
              {doubts.map((d, i) => (
                <div key={i} className="bg-gray-700 rounded-lg p-3">
                  <div className="flex items-center gap-2 mb-1"><span className="font-bold text-sm">{d.user}</span><span className="text-xs text-gray-400">{d.time}</span></div>
                  <p className="text-sm text-gray-300">{d.msg}</p>
                </div>
              ))}
            </div>
            <div className="flex gap-2">
              <input value={doubtMsg} onChange={(e) => setDoubtMsg(e.target.value)} placeholder="Type your question..." className={`flex-1 border rounded-lg px-4 py-2 focus:outline-none focus:border-blue-500 ${
                theme === 'dark' ? 'bg-gray-700 border-gray-600 text-white placeholder-gray-400' : 'bg-gray-100 border-gray-300 text-gray-900 placeholder-gray-500'
              }`} />
              <button onClick={sendDoubt} className="px-4 py-2 bg-purple-600 hover:bg-purple-500 rounded-lg">Send</button>
            </div>
          </div>
        </div>

        <div className="space-y-4">
          <div className="bg-gray-800 rounded-xl overflow-hidden">
            <div className="bg-gray-900 px-4 py-3 flex items-center justify-between border-b border-gray-700">
              <div className="flex items-center gap-2"><Code size={18} className="text-gray-400" /><span className="text-sm font-medium text-gray-300">main.{selectedLang === 'javascript' ? 'js' : selectedLang === 'python' ? 'py' : selectedLang}</span></div>
              <button onClick={runCode} className="flex items-center gap-2 px-4 py-2 bg-green-600 hover:bg-green-500 rounded-lg text-sm font-medium"><Play size={16} /> Run Code</button>
            </div>
            <Editor height="300px" language={selectedLang === 'html' ? 'html' : selectedLang === 'css' ? 'css' : selectedLang} value={code} onChange={setCode} theme="vs-dark" options={{ minimap: { enabled: false }, fontSize: 14, lineNumbers: 'on', scrollBeyondLastLine: false, automaticLayout: true }} />
          </div>

          <div className="bg-gray-800 rounded-xl p-4">
            <div className="flex items-center gap-2 mb-3"><div className={`w-2 h-2 rounded-full ${output ? 'bg-green-500' : 'bg-gray-500'}`} /><span className="text-sm font-medium text-gray-300">Output</span></div>
            <div className="bg-gray-900 rounded-lg p-4 font-mono text-sm min-h-[80px]">{output ? <span className="text-green-400">{output}</span> : <span className="text-gray-500">Click "Run Code" to see output...</span>}</div>
          </div>

          {completed.includes(`${selectedLang}-${currentLesson}`) && (
            <div className="bg-green-500/20 border border-green-500/50 rounded-xl p-4 flex items-center gap-3">
              <CheckCircle size={24} className="text-green-500" />
              <div><p className="font-bold text-green-400">Lesson Complete!</p><p className="text-sm text-green-300">+10 XP earned</p></div>
            </div>
          )}

          <div className="grid grid-cols-3 gap-4">
            <div className="bg-gray-800 rounded-xl p-4 text-center"><p className="text-2xl font-bold text-blue-400">{completed.length}</p><p className="text-xs text-gray-400">Completed</p></div>
            <div className="bg-gray-800 rounded-xl p-4 text-center"><p className="text-2xl font-bold text-purple-400">{LESSONS[selectedLang].length}</p><p className="text-xs text-gray-400">Lessons</p></div>
            <div className="bg-gray-800 rounded-xl p-4 text-center"><p className="text-2xl font-bold text-orange-400">{LANGUAGES.length}</p><p className="text-xs text-gray-400">Languages</p></div>
          </div>
        </div>
      </main>
    </div>
  );
}

export default App;
